var e=[{id:`L2_1`,type:`dialog`,speaker:`SIGMA_RAS_NEXT_NULL`,text:{KOREA:`받아라! 어퍼컷!`,JPN:`くらえ！　アッパーカット！`,ENG:`Take this! Uppercut!`,TWN:`吃我一記！上勾拳！`},stage:{bg:`COLOSSEUM`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SIGMA_RAS_NEXT_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`HAVEN_HAVEN_NULL_NULL`,text:{KOREA:`하악… 하악… 크학!!`,JPN:`はあっ……はあっ……ぐはっ！！`,ENG:`*Huff...* *Huff...* Kaagh!!`,TWN:`呃啊…呃啊…呃啊！！`},stage:{bg:`COLOSSEUM`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HAVEN_HAVEN_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L4_1`,type:`dialog`,speaker:`SIGMA_RAS_NEXT_NULL`,text:{KOREA:`정신 차려, 루트! 술래잡기는 힘이 아니라 재치가 필요하다구!`,JPN:`しっかりして、ルート！　鬼ごっこは力じゃなくて機転が必要なんだよ！`,ENG:`Come on, Root! Being "it" isn’t about power, it’s about wits!`,TWN:`路特，打起精神來！鬼抓人靠的不是蠻力而是技巧！`},stage:{bg:`COLOSSEUM`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SIGMA_RAS_NEXT_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`굉장한데, 저 꼬마! 요리조리 잘만 피하잖아!`,JPN:`あのガキ、すげえな！　あちこちうまく避けてる！`,ENG:`Look at her go! She's evading all of his attacks!`,TWN:`那小鬼好厲害！好會閃！`},stage:{bg:`COLOSSEUM`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:null,text:{KOREA:`헤이븐 형님! 그런 꼬맹이 단번에 붙잡아 버려요!`,JPN:`ヘイブン兄貴！　そんなガキなんか一気に捕まえちゃって！`,ENG:`Mr. Haven! Catch that little bugger!`,TWN:`天堂大哥！一下就可以逮到那個小鬼的！`},stage:{bg:`COLOSSEUM`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:null,text:{KOREA:`꼬마야! 얼마 안 남았어! 잘 좀 피해 봐!`,JPN:`おい、ガキ！　あとちょっとだ！　ちゃんと避けろよ！`,ENG:`Hey kid! It's almost over! Hang in there!`,TWN:`小鬼！時間剩不多，閃好！`},stage:{bg:`COLOSSEUM`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:null,R:null}}},{id:`L9_1`,type:`dialog`,speaker:`SIGMA_RAS_NEXT_NULL`,text:{KOREA:`자, 루트! 술래잡기의 최종 보스! 시그마 님께 도전하시라!`,JPN:`さあ、ルート！　鬼ごっこの最終ボス！　シグマ様に挑戦しろ！`,ENG:`Okay, Root! Challenge Sigma, the hidden boss of tag!`,TWN:`來吧，路特！鬼抓人的最終BOSS！來挑戰西格瑪大人吧！`},stage:{bg:`COLOSSEUM`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SIGMA_RAS_NEXT_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`SIGMA_RAS_NEXT_NULL`,text:{KOREA:`앗!?`,JPN:`あっ！？`,ENG:`Ah!?`,TWN:`嗯！？`},stage:{bg:`COLOSSEUM`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SIGMA_RAS_NEXT_NULL`,face:`UNIT_SURPRISE`},R:null}},sfx:`FX_COMBAT_ALL_HIT_ROCK_BIG_02`},{id:`L11_1`,type:`dialog`,speaker:`HAVEN_HAVEN_NULL_NULL`,text:{KOREA:`크으아아……!!`,JPN:`ぐぅああ……！！`,ENG:`Kraagh...!`,TWN:`呃啊啊啊……！`},stage:{bg:`COLOSSEUM`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HAVEN_HAVEN_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`SIGMA_RAS_NEXT_NULL`,text:{KOREA:`좋아! 이제 내가 술래!`,JPN:`よし！　これで私が鬼ね！`,ENG:`Okay! Now I'm "it"!`,TWN:`好！這次換我當鬼！`},stage:{bg:`COLOSSEUM`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`SIGMA_RAS_NEXT_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`HAVEN_HAVEN_NULL_NULL`,text:{KOREA:`……아?`,JPN:`……あ？`,ENG:`Huh...?`,TWN:`……喔？`},stage:{bg:`COLOSSEUM`,bgm:null,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`HAVEN_HAVEN_NULL_NULL`,face:`UNIT_SERIOUS2`},R:null}}}];export{e as default};